BEGIN;

ON CONFLICT (urdu_phrase) DO UPDATE SET
  romanised = EXCLUDED.romanised,
  meaning_urdu = EXCLUDED.meaning_urdu,
  example_sentence = EXCLUDED.example_sentence,
  category = EXCLUDED.category,
  difficulty = EXCLUDED.difficulty,
  image_url = EXCLUDED.image_url,
  reveal_image_url = EXCLUDED.reveal_image_url,
  is_active = EXCLUDED.is_active;

DELETE FROM wrong_options WHERE phrase_id IN (SELECT id FROM phrases WHERE urdu_phrase IN ('طوطے اڑ جانا', 'ہاتھ صاف کرنا', 'دانتوں تلے انگلی دبانا', 'آنکھوں کا تارا ہونا', 'رگوں میں بس جانا', 'چکا چوند ہونا', 'آگ بگولہ ہونا', 'باغ باغ ہونا', 'اونچی دکان پھیکا پکوان', 'آگ لگنے پر کنواں کھودنا', 'آستین کا سانپ ہونا', 'گڑے مردے اکھاڑنا', 'ہاتھ پاؤں مارنا', 'کان کھڑے ہونا', 'ناک میں دم کرنا', 'پیٹھ پیچھے بات کرنا'));
DELETE FROM phrase_options WHERE phrase_id IN (SELECT id FROM phrases WHERE urdu_phrase IN ('طوطے اڑ جانا', 'ہاتھ صاف کرنا', 'دانتوں تلے انگلی دبانا', 'آنکھوں کا تارا ہونا', 'رگوں میں بس جانا', 'چکا چوند ہونا', 'آگ بگولہ ہونا', 'باغ باغ ہونا', 'اونچی دکان پھیکا پکوان', 'آگ لگنے پر کنواں کھودنا', 'آستین کا سانپ ہونا', 'گڑے مردے اکھاڑنا', 'ہاتھ پاؤں مارنا', 'کان کھڑے ہونا', 'ناک میں دم کرنا', 'پیٹھ پیچھے بات کرنا'));



COMMIT;